const isDark = await storage.get('tf_dark_mode');
if (isDark) {
  const id = await storage.get('tf_dark_css_id');
  if (id) await dom.removeCSS(id);
  await storage.set('tf_dark_mode', false);
  await spinner.show("☀️ Dark mode off");
  setTimeout(() => spinner.hide(), 1200);
} else {
  const id = await dom.injectCSS(`
    html { filter: invert(1) hue-rotate(180deg) !important; }
    img, video, iframe, canvas, svg, [style*="background-image"] {
      filter: invert(1) hue-rotate(180deg) !important;
    }
  `);
  await storage.set('tf_dark_css_id', id);
  await storage.set('tf_dark_mode', true);
  await spinner.show("🌙 Dark mode on");
  setTimeout(() => spinner.hide(), 1200);
}
